# Comprehensive audit of all 3 customers
customer_ids = ['CUST-8842', 'CUST-2244', 'CUST-5501']

# Step 1: Get all customer profiles
profiles = {}
for cid in customer_ids:
    profiles[cid] = tool('get_customer', customer_id=cid)

# Step 2: Get order history for all customers
order_histories = {}
for cid in customer_ids:
    order_histories[cid] = tool('get_order_history', customer_id=cid)

# Step 3: Collect all non-returned orders and look up their details
all_orders_detail = {}
all_skus = []

for cid in customer_ids:
    orders = order_histories[cid]['orders']
    non_returned = [o for o in orders if o['status'] != 'returned']

    for order in non_returned:
        order_detail = tool('lookup_order', order_id=order['id'])
        all_orders_detail[order['id']] = order_detail

        # Collect all SKUs from this order
        for item in order_detail['items']:
            all_skus.append(item['sku'])

# Step 4: Check inventory for all SKUs
inventory_result = tool('check_inventory', sku_list=all_skus)
inventory_by_sku = {}
for item in inventory_result['items']:
    sku = item['sku']
    if sku not in inventory_by_sku:
        inventory_by_sku[sku] = []
    inventory_by_sku[sku].append(item)

# Step 5: Build audit results per customer and identify out-of-stock items
audit_results = {}
out_of_stock_items = []

for cid in customer_ids:
    profile = profiles[cid]
    orders = order_histories[cid]['orders']
    non_returned = [o for o in orders if o['status'] != 'returned']

    customer_audit = {
        'customer_id': cid,
        'name': profile['name'],
        'email': profile['email'],
        'tier': profile['tier'],
        'loyalty_points': profile['loyalty_points'],
        'account_status': profile['account_status'],
        'total_orders': len(orders),
        'non_returned_orders': len(non_returned),
        'orders_detail': [],
        'out_of_stock_items': []
    }

    for order in non_returned:
        order_detail = all_orders_detail[order['id']]
        order_info = {
            'order_id': order['id'],
            'date': order['date'],
            'status': order['status'],
            'total': order['total'],
            'items': []
        }

        for item in order_detail['items']:
            sku = item['sku']
            inv_data = inventory_by_sku.get(sku, [])

            item_info = {
                'sku': sku,
                'name': item['name'],
                'price': item['price'],
                'inventory': inv_data
            }

            # Check if out of stock in all warehouses
            is_out_of_stock = True
            for inv in inv_data:
                if inv['available'] > 0:
                    is_out_of_stock = False
                    break

            if is_out_of_stock and len(inv_data) > 0:
                item_info['out_of_stock'] = True
                customer_audit['out_of_stock_items'].append({
                    'sku': sku,
                    'name': item['name'],
                    'order_id': order['id']
                })
                out_of_stock_items.append({
                    'customer_id': cid,
                    'sku': sku,
                    'name': item['name'],
                    'order_id': order['id']
                })
            else:
                item_info['out_of_stock'] = False

            order_info['items'].append(item_info)

        customer_audit['orders_detail'].append(order_info)

    audit_results[cid] = customer_audit

# Step 6: Send summary emails to each customer
email_results = []

for cid in customer_ids:
    audit = audit_results[cid]
    email = audit['email']

    # Build email body
    body = f"""Dear {audit['name']},

This is your account audit summary as of 2026-03-10.

ACCOUNT INFORMATION:
- Membership Tier: {audit['tier']}
- Loyalty Points: {audit['loyalty_points']}
- Account Status: {audit['account_status']}
- Total Orders: {audit['total_orders']}
- Non-Returned Orders Audited: {audit['non_returned_orders']}

ORDER DETAILS:
"""

    for order in audit['orders_detail']:
        body += f"\nOrder {order['order_id']} ({order['date']}) - Status: {order['status']} - Total: ${order['total']}\n"
        for item in order['items']:
            stock_status = "OUT OF STOCK" if item['out_of_stock'] else "In Stock"
            body += f"  • {item['name']} (SKU: {item['sku']}) - ${item['price']} - {stock_status}\n"

    if audit['out_of_stock_items']:
        body += f"\n⚠️  ALERT: {len(audit['out_of_stock_items'])} item(s) currently out of stock:\n"
        for item in audit['out_of_stock_items']:
            body += f"  • {item['name']} (SKU: {item['sku']}) in Order {item['order_id']}\n"
    else:
        body += "\n✓ All items in your orders are in stock.\n"

    body += "\nBest regards,\nAudit Team"

    email_result = tool('send_notification', 
                       channel='email',
                       recipient=email,
                       subject=f'Account Audit Summary - {cid}',
                       body=body)
    email_results.append(email_result)

# Final summary
summary = {
    'audit_date': '2026-03-10',
    'customers_audited': len(customer_ids),
    'total_orders_reviewed': sum(len(audit_results[cid]['orders_detail']) for cid in customer_ids),
    'total_out_of_stock_items': len(out_of_stock_items),
    'out_of_stock_items': out_of_stock_items,
    'emails_sent': len(email_results),
    'customer_audits': audit_results,
    'email_delivery_status': email_results
}

summary
